SELECT count(*) FROM movie_keyword, keyword, title, movie_companies, company_type, cast_info, movie_info WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id;